import { Skeleton } from ':components/Skeleton';
import { classNames } from ':helpers/classnames';
import React from 'react';

export interface NavigationItemSkeletonProps {
	/**
	 * Дополнительный CSS класс
	 */
	className?: string;
	/**
	 * Является ли элемент дочерним (второй уровень)
	 */
	isChild?: boolean;
	/**
	 * Анимация скелетона
	 */
	animated?: boolean;
}

/**
 * Компонент для отображения состояния загрузки элемента навигации
 * Показывает кружок (иконка) и линию (текст) справа от него
 */
export const NavigationItemSkeleton: React.FC<NavigationItemSkeletonProps> = ({
	className,
	isChild = false,
	animated = true,
}) => {
	return (
		<div
			className={classNames(
				'navigation-item-skeleton',
				{
					'navigation-item-skeleton--child': isChild,
				},
				className,
			)}
		>
			{/* Кружок для иконки */}
			<Skeleton
				variant="circle"
				width={24}
				height={24}
				animated={animated}
				className="navigation-item-skeleton__icon"
			/>
			{/* Линия для текста */}
			<Skeleton variant="line" height={24} width="60%" animated={animated} className="navigation-item-skeleton__text" />
		</div>
	);
};
